using System;
using System.IO;
using System.Linq;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.StaticFiles;

namespace FileUploadExample.Controllers
{
    [Route("api/[controller]")]
    [ApiController]
    public class UploadController : ControllerBase
    {
        private readonly string[] permittedExtensions = { ".jpg", ".jpeg", ".png", ".gif", ".bmp", ".pdf", ".doc", ".docx", ".xls", ".xlsx", ".ppt", ".pptx" };
        private readonly long fileSizeLimit = 10 * 1024 * 1024; // 10 MB
        private readonly string uploadFolder = Path.Combine(Directory.GetCurrentDirectory(), "wwwroot", "uploads");

        [HttpPost("upload")]
        public async Task<IActionResult> UploadFile(IFormFile file)
        {
            if (file == null || file.Length == 0)
            {
                return BadRequest("No file uploaded.");
            }

            if (file.Length > fileSizeLimit)
            {
                return BadRequest("File size exceeds the limit.");
            }

            var fileExtension = Path.GetExtension(file.FileName).ToLowerInvariant();
            if (string.IsNullOrEmpty(fileExtension) || !permittedExtensions.Contains(fileExtension))
            {
                return BadRequest("Invalid file type.");
            }

            var trustedFileNameForFileStorage = Path.GetRandomFileName() + fileExtension;
            var filePath = Path.Combine(uploadFolder, trustedFileNameForFileStorage);

            Directory.CreateDirectory(uploadFolder);

            using (var fileStream = new FileStream(filePath, FileMode.Create))
            {
                await file.CopyToAsync(fileStream);
            }

            return Ok(new { FilePath = $"/uploads/{trustedFileNameForFileStorage}" });
        }
    }
}